interface TicketCursor { createdAt: string; id: string; }
function decodeCursor(cursor: string): TicketCursor {
  const parsed = JSON.parse(Buffer.from(cursor, 'base64url').toString('utf8')) as TicketCursor;
  if (!parsed.createdAt || Number.isNaN(Date.parse(parsed.createdAt)) || !parsed.id) throw new Error('bad_cursor');
  return parsed;
}

async function list(cursor?: string) {
  const limit = 30;
  const c = cursor ? decodeCursor(cursor) : null;
  const where = c ? 'WHERE (created_at, id) < ($1::timestamptz, $2)' : '';
  const params = c ? [c.createdAt, c.id] : [];
  return db.query(
    `SELECT * FROM tickets ${where} ORDER BY created_at DESC, id DESC LIMIT $${params.length + 1}`,
    [...params, limit],
  );
}

