const WINDOW = 60_000;
const LIMIT = 120;
async function checkLimit(userId: string) {
  const now = Date.now();
  const current = Math.floor(now / WINDOW);
  const key = `rl:${userId}:${current}`;
  const count = await redis.incr(key);
  if (count === 1) await redis.pexpire(key, WINDOW * 2);
  const prev = Number(await redis.get(`rl:${userId}:${current - 1}`) || 0);
  const elapsed = now % WINDOW;
  const estimate = prev * ((WINDOW - elapsed) / WINDOW) + count;
  if (estimate > LIMIT) throw new RateLimitError();
}

